import type { IMoveContext, IPlayer } from '../../types'
import { GomokuPlayerType } from '../constant'
import { BasePlayer } from './BasePlayer'

export class HumanPlayer extends BasePlayer implements IPlayer {
  public readonly type: GomokuPlayerType = GomokuPlayerType.HUMAN
  public readonly automatic: boolean = false

  protected override _move(ctx: IMoveContext): [r: number, c: number] {
    if (ctx.clickedPos != null) {
      const { r, c } = ctx.clickedPos
      return [r, c]
    }
    return [-1, -1]
  }
}
