import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { DOUBLE_PI } from '../constant'
import type { IGomokuPieceDrawer } from './GomokuPieceDrawer'

export interface IGomokuListeners {
  onClick?(r: number, c: number): void
}

export interface IGomokuStyle {
  gridLineColor: string
  locatePointColor: string
}

export interface IGomokuDrawerProps {
  canvas: HTMLCanvasElement | null
  /**
   * The number of horizontal or vertical lines on the board.
   */
  lines: number
  /**
   * The pieces on the gomoku board.
   */
  pieces: ReadonlyArray<IGomokuPiece>
  /**
   * Piece map.
   */
  pieceDrawer: Readonly<IGomokuPieceDrawer> | null
  /**
   * Width of the board line.
   */
  lineWidth?: number
  /**
   * Radius of a chess piece.
   */
  pieceRadius?: number
  /**
   * Gomoku style.
   */
  styles?: Partial<IGomokuStyle>
  /**
   *
   * @param r
   * @param c
   */
  listeners?: IGomokuListeners
}

export class GomokuDrawer {
  protected GOMOKU_SIZE: number
  protected canvas: HTMLCanvasElement | null = null
  protected context: CanvasRenderingContext2D | null = null
  protected pieceDrawer: Readonly<IGomokuPieceDrawer> | null = null
  protected styles: IGomokuStyle
  protected readonly listeners: IGomokuListeners
  protected readonly __customPieceRadius?: number

  protected pieces: ReadonlyArray<IGomokuPiece>
  protected lineWidth: number
  protected pieceRadius = 0
  protected gridSize = 0
  protected farTop = 0
  protected farRight = 0
  protected farBottom = 0
  protected farLeft = 0
  protected activateCell: { r: number; c: number } = { r: -1, c: -1 }

  constructor(props: IGomokuDrawerProps) {
    this.GOMOKU_SIZE = props.lines
    this.pieces = props.pieces
    this.lineWidth = props.lineWidth ?? 1
    this.pieceDrawer = props.pieceDrawer
    this.listeners = { ...props.listeners }
    this.styles = {
      gridLineColor: props.styles?.gridLineColor ?? '#492d15',
      locatePointColor: props.styles?.locatePointColor ?? '#333333',
    }
    this.__customPieceRadius = props.pieceRadius
    this.init(props.canvas)
  }

  protected init(canvas: HTMLCanvasElement | null): void {
    this.canvas = canvas
    this.context = canvas != null ? canvas.getContext('2d') : null
    window.addEventListener('resize', this.onresize)
    this.canvas?.addEventListener('click', this.onclick)
    this.onresize()
  }

  public reset(preference: {
    canvas: HTMLCanvasElement | null
    GOMOKU_SIZE?: number
    pieceDrawer?: Readonly<IGomokuPieceDrawer>
    styles?: Partial<IGomokuStyle>
  }): void {
    if (preference.GOMOKU_SIZE != null) this.GOMOKU_SIZE = preference.GOMOKU_SIZE
    if (preference.pieceDrawer != null) this.pieceDrawer = preference.pieceDrawer
    if (preference.styles != null) this.styles = { ...this.styles, ...preference.styles }
    if (this.canvas !== preference.canvas) {
      this.destroy()
      this.init(preference.canvas)
    }
    this.onresize()
  }

  /**
   * Perform clean operations.
   */
  public destroy(): void {
    // Remove event listeners.
    window.removeEventListener('resize', this.onresize)
    this.canvas?.removeEventListener('click', this.onclick)
  }

  public draw(pieces?: ReadonlyArray<IGomokuPiece>): void {
    const { canvas, context } = this
    if (canvas == null || context == null) return

    if (pieces != null) this.pieces = pieces
    context.clearRect(0, 0, canvas.width, canvas.height)
    this.drawBoard()
    this.drawLocatePoints()
    this.drawPieces()
    this.highlightLastPlacedPiece()
    this.highlightActivateCell()
  }

  protected drawBoard(): void {
    const { context, lineWidth, farTop, farRight, farBottom, farLeft, gridSize, styles } = this
    if (context == null) return

    const step: number = gridSize + lineWidth

    // Set style
    context.lineWidth = lineWidth
    context.strokeStyle = styles.gridLineColor

    context.beginPath()
    {
      // render row
      for (let x = farTop; x <= farBottom; x += step) {
        context.moveTo(x, farLeft)
        context.lineTo(x, farRight)
      }

      // render column
      for (let x = farLeft; x <= farRight; x += step) {
        context.moveTo(farTop, x)
        context.lineTo(farBottom, x)
      }
    }
    context.closePath()
    context.stroke()
  }

  protected drawLocatePoints(): void {
    const { context, lineWidth, GOMOKU_SIZE: lines, styles } = this
    if (context == null) return

    const mid: number = (lines - 1) >> 1
    const start = mid % 4 === 0 ? 4 : mid % 4
    const radius: number = (lineWidth + 6) >> 1

    // Set style
    context.fillStyle = styles.locatePointColor
    for (let r = start; r + 1 < lines; r += 4) {
      for (let c = start; c + 1 < lines; c += 4) {
        const { x, y } = this.position(r, c)
        context.beginPath()
        context.arc(x, y, radius, 0, DOUBLE_PI, false)
        context.closePath()
        context.stroke()
        context.fill()
      }
    }
  }

  protected drawPieces(): void {
    const { context, GOMOKU_SIZE, pieceDrawer, pieceRadius, pieces } = this
    if (context == null || pieceDrawer == null) return

    for (const { r, c, p } of pieces) {
      if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
        const { x, y } = this.position(r, c)
        pieceDrawer.draw(context, p, x, y, pieceRadius)
      }
    }
  }

  protected highlightLastPlacedPiece(): void {
    const { GOMOKU_SIZE, context, pieces, pieceRadius, activateCell } = this
    if (context == null) return
    if (pieces.length <= 0) return

    const { r, c } = pieces[pieces.length - 1]
    if (r === activateCell.r && c === activateCell.c) return

    if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
      const radius: number = pieceRadius + 4

      const { x, y } = this.position(r, c)
      context.setLineDash([5, 3])
      context.lineWidth = 1
      context.strokeStyle = '#c80000'
      context.beginPath()
      context.arc(x, y, radius, 0, DOUBLE_PI, false)
      context.closePath()
      context.stroke()
      context.setLineDash([])
    }
  }

  protected highlightActivateCell(): void {
    const { GOMOKU_SIZE, context, activateCell, pieceRadius } = this
    if (context == null) return

    const { r, c } = activateCell
    if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
      const radius: number = pieceRadius + 4

      const { x, y } = this.position(r, c)
      context.setLineDash([5, 3])
      context.lineWidth = 1
      context.strokeStyle = 'blue'
      context.beginPath()
      context.arc(x, y, radius, 0, DOUBLE_PI, false)
      context.closePath()
      context.stroke()
      context.setLineDash([])
    }
  }

  protected locate(x: number, y: number): { r: number; c: number } {
    const { GOMOKU_SIZE: lines, pieceRadius } = this

    const step: number = this.gridSize + this.lineWidth
    const X: number = x - this.farLeft
    const Y: number = y - this.farTop

    let r: number = Math.floor(Y / step)
    let c: number = Math.floor(X / step)
    let dx: number = X - c * step
    let dy: number = Y - r * step

    if (dx * 2 > step) {
      c += 1
      dx = step - dx
    }

    if (dy * 2 > step) {
      r += 1
      dy = step - dy
    }

    return r >= 0 &&
      r < lines &&
      c >= 0 &&
      c < lines &&
      Math.abs(dx) <= pieceRadius &&
      Math.abs(dy) <= pieceRadius
      ? { r, c }
      : { r: -1, c: -1 }
  }

  protected position(r: number, c: number): { x: number; y: number } {
    const { lineWidth, gridSize, farLeft, farTop } = this
    const step: number = gridSize + lineWidth
    const x: number = farLeft + c * step
    const y: number = farTop + r * step
    return { x, y }
  }

  protected readonly onresize = (): void => {
    const { canvas, GOMOKU_SIZE: lines, lineWidth } = this
    if (canvas == null) return

    const container = canvas.parentElement
    if (container != null) {
      const _size = Math.min(container.clientWidth, container.clientHeight)
      const widthOfLines: number = lineWidth * lines
      const gridSize: number = Math.floor((_size - widthOfLines) / (lines + 0.2))

      if (gridSize < 12) {
        throw new TypeError(
          `Canvas is not large enough. clientWidth(${container.clientWidth}), clientHeight(${container.clientHeight})`,
        )
      }

      canvas.width = _size
      canvas.height = _size

      const remainSize = _size - widthOfLines - gridSize * (lines - 1)
      this.farLeft = this.farTop = Math.floor(remainSize / 2)
      this.farRight = this.farBottom = _size - (remainSize - this.farLeft)
      this.gridSize = gridSize

      const basePieceRadius: number = Math.round((this.lineWidth + 16) / 2) + 1
      this.pieceRadius =
        this.__customPieceRadius ??
        Math.floor(Math.min(gridSize * 0.4, Math.max(this.gridSize * 0.3, basePieceRadius)))
      this.draw()
    }
  }

  protected readonly onclick = (evt: MouseEvent): void => {
    const { GOMOKU_SIZE } = this
    const { offsetX: x, offsetY: y } = evt
    const { r, c } = this.locate(x, y)
    if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
      this.updateActivateCell(r, c)
      this.listeners.onClick?.(r, c)
    }
  }

  protected updateActivateCell(r: number, c: number): void {
    this.activateCell.r = r
    this.activateCell.c = c
    this.draw()
  }
}
