import invariant from '@guanghechen/invariant'
import { sleep } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import { GomokuContextType } from '../context/Provider'
import { createPlayer } from '../core/player/createPlayer'
import type { IMoveContext, IPlayer } from '../types'

export interface IMover {
  move(clickedPos?: { r: number; c: number }): void | Promise<void>
}

export const useMover = (): IMover => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [MAX_ROW, MAX_COL, gameStatus, pieces, playersData, moverId, action] = useGomokuStore(
    ({ state, action }) => [
      state.MAX_ROW,
      state.MAX_COL,
      state.gameStatus,
      state.pieces,
      state.players,
      state.mover,
      action,
    ],
  )

  const playersRef = React.useRef<IPlayer[]>([])
  if (playersRef.current[moverId]?.type !== playersData[moverId].type) {
    playersRef.current[moverId] = createPlayer(playersData[moverId])
  }
  const currentPlayer: IPlayer | undefined = playersRef.current[moverId]

  const gameLockRef = React.useRef<boolean>(false)
  const move = useEvent(async (clickedPos?: { r: number; c: number }): Promise<void> => {
    if (gameLockRef.current || currentPlayer === undefined) return
    if (gameStatus !== GameRunningStatus.RUNNING) return

    const moveContext: IMoveContext = {
      MAX_ROW,
      MAX_COL,
      pieces,
      playerId: moverId,
      clickedPos,
    }

    try {
      gameLockRef.current = true
      const [r, c] = await currentPlayer.move(moveContext)
      invariant(
        r >= 0 && r < MAX_ROW && c >= 0 && c <= MAX_COL,
        () => `[Unexpected moving] currentPlayer(${moverId}}), moving: (${r}, ${c})`,
      )
      action.move(r, c)
    } finally {
      gameLockRef.current = false
      await sleep(50)
    }
  })

  React.useEffect(() => {
    if (gameStatus !== GameRunningStatus.RUNNING) return
    if (currentPlayer.automatic) {
      // Don't block rendering.
      const timeout = setTimeout(() => void move(), 0) as unknown as number
      return (): void => clearTimeout(timeout)
    }
  }, [currentPlayer, move, gameStatus])
  return { move }
}
