import type { IColor, IColorOrImage } from '@kyokuya/core-util'
import type { IGomokuCoreState } from '@kyokuya/react-game-gomoku-core'
import { initGomokuCoreState } from '@kyokuya/react-game-gomoku-core'
import { GomokuPlayerType } from '../core/constant'
import type { IGomokuPlayer } from '../types'

export interface IGomokuState extends IGomokuCoreState {
  /**
   * Total players.
   */
  players: IGomokuPlayer[]
  /**
   * Background of gomoku board.
   */
  boardBackground: IColorOrImage
  borderColor: IColor
  locatePointColor: IColor
}

export const defaultGomokuState: IGomokuState = initGomokuState()

export function initGomokuState(initialState?: Partial<IGomokuState>): IGomokuState {
  const { MAX_ROW, MAX_COL, ...baseState }: IGomokuCoreState = initGomokuCoreState(initialState)
  const players: IGomokuPlayer[] = [
    {
      name: 'guanghechen',
      type: GomokuPlayerType.COMPUTER,
      ...initialState?.players?.[1],
      preferenceSettings: {
        pieceFillStyle: {
          prefer: 'image',
          imageUrl: '/assets/img/gomoku/guanghechen.jpg',
        },
        ...initialState?.[1]?.preferenceSettings,
      },
    },
    {
      name: 'wulala',
      type: GomokuPlayerType.HUMAN,
      ...initialState?.players?.[0],
      preferenceSettings: {
        pieceFillStyle: {
          prefer: 'image',
          imageUrl: '/assets/img/gomoku/wulala.jpg',
        },
        pieceStrokeStyle: '#eee',
        ...initialState?.[0]?.preferenceSettings,
      },
    },
  ]
  return {
    ...baseState,
    MAX_ROW,
    MAX_COL,
    players,
    boardBackground: {
      prefer: 'color',
      color: { r: 230, g: 226, b: 222, a: 1 },
      imageUrl: '/assets/img/gomoku/board.jpg',
      ...initialState?.boardBackground,
    },
    borderColor: initialState?.borderColor ?? { r: 255, g: 255, b: 255, a: 1 },
    locatePointColor: initialState?.locatePointColor ?? { r: 51, g: 51, b: 51, a: 1 },
  }
}
