import { cx } from '@emotion/css'
import { ColorPicker } from '@kyokuya/core-component'
import type { IColor } from '@kyokuya/core-util'
import { calcCssColor, mergeStyleSets } from '@kyokuya/core-util'
import { useEvent } from '@kyokuya/react-hooks'
import { Button } from '@mui/material'
import React from 'react'
import { defaultGomokuState } from '../context/state'

export interface IGameSettingsBorderProps {
  disabled: boolean
  border: IColor
  className?: string
  onBorderChange?(border: IColor): void
}

export const GomokuSettingsBorder: React.FC<IGameSettingsBorderProps> = props => {
  const { disabled } = props
  const [border, setBorder] = React.useState<IColor>(props.border)
  const [pickerVisible, setPickerVisible] = React.useState<boolean>(false)

  const events = {
    onTogglePickerVisible: useEvent(() => {
      if (disabled) return
      setPickerVisible(v => !v)
    }),
    onColorChange: useEvent((color: IColor): void => {
      if (disabled) return
      setBorder(color)
      props.onBorderChange?.(color)
    }),
    onResetColor: useEvent(() => {
      if (disabled) return
      const nextBorder: IColor = { ...defaultGomokuState.borderColor }
      setBorder(nextBorder)
      props.onBorderChange?.(nextBorder)
    }),
  }

  const classes = useStyles(border, disabled)
  return (
    <div className={cx(classes.container, props.className)}>
      <span className={classes.label}>Border:</span>
      <div className={classes.swatch} onClick={events.onTogglePickerVisible}>
        <div className={classes.colorSquare} />
      </div>
      <ColorPicker
        visible={pickerVisible}
        color={border}
        onVisibleChange={setPickerVisible}
        onColorChange={events.onColorChange}
      />
      <div>
        <Button disabled={disabled} className={classes.resetColorBth} onClick={events.onResetColor}>
          (reset)
        </Button>
      </div>
    </div>
  )
}

const useStyles = (color: IColor, disabled: boolean) => {
  return React.useMemo(
    () =>
      mergeStyleSets({
        container: {
          display: 'flex',
          alignItems: 'center',
        },
        label: {
          userSelect: 'none',
        },
        swatch: {
          display: 'inline-block',
          padding: 3,
          border: '1px solid rgba(0,0,0,.2)',
          borderRadius: '1px',
          background: '#fff',
          cursor: disabled ? 'default' : 'pointer',
          '&&': {
            marginLeft: '1rem',
          },
        },
        colorSquare: {
          width: 32,
          height: 12,
          borderRadius: 2,
          backgroundColor: calcCssColor(color),
        },
        resetColorBth: {
          '&&': {
            textTransform: 'none',
          },
        },
      }),
    [color],
  )
}
