import React from 'react'
import shallow from 'zustand/shallow'
import { GomokuContextType } from '../context/Provider'
import type { IGomokuState } from '../context/state'

export interface IGomokuPersistentProps {
  onStateChange(state: IGomokuState): Promise<void> | void
}

export const GomokuPersistent: React.FC<IGomokuPersistentProps> = ({ onStateChange }) => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [state, pause] = useGomokuStore(store => [store.state, store.action.pause], shallow)

  React.useEffect(() => {
    const beforeunload = (): void => pause()
    window.addEventListener('beforeunload', beforeunload)
    return () => window.removeEventListener('beforeunload', beforeunload)
  }, [pause])

  React.useEffect(() => {
    if (state !== null) {
      void onStateChange(state)
    }
  }, [state, onStateChange])
  return <React.Fragment />
}
