import { WebWorkerTaskScheduler } from '@kyokuya/web-worker'
import { Constants } from '@/core/constant'
import type { IRequestData, IResponseData, IServiceMoveRequestData } from '../types'
import { ServiceType } from '../types'

const scheduler = new WebWorkerTaskScheduler<ServiceType, IRequestData, IResponseData>({
  canUseDOM: Constants.canUseDOM,
  workerUrl: '/assets/js/webworker/gomoku.js',
  workerInstanceCount: 1,
  MAX_TASK_NUMBER: 10,
})

export async function move(requestData: IServiceMoveRequestData): Promise<[r: number, c: number]> {
  const responseData = await scheduler.run(ServiceType.MOVE, requestData)
  if (responseData === null) return [-1, -1]
  const { r, c } = responseData
  return [r, c]
}
