import { cx } from '@emotion/css'
import { useEvent } from '@guanghechen/react-hooks'
import { mergeStyleSets } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import SettingIcon from '@mui/icons-material/Settings'
import { Button, Dialog, DialogActions, DialogContent, IconButton } from '@mui/material'
import React from 'react'
import shallow from 'zustand/shallow'
import { GameSettings } from '../component/GomokuSettings'
import { GomokuContextType } from '../context/Provider'

export interface IGameSettingsWakeBtnProps {
  onWakeUp(): void
}

const DefaultWakeBtn: React.FC<IGameSettingsWakeBtnProps> = props => {
  return (
    <IconButton size="small" className={classes.wakeBtn} onClick={props.onWakeUp}>
      <SettingIcon />
    </IconButton>
  )
}

export interface IGameSettingsContainerProps {
  containerRef: React.RefObject<HTMLDivElement>
  className?: string
  WakeBtn?: React.ComponentType<IGameSettingsWakeBtnProps>
}

export const GameSettingsContainer: React.FC<IGameSettingsContainerProps> = props => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const settingsRef = React.useRef<GameSettings>(null)
  const [MAX_ROW, gameStatus, boardBackground, borderColor, syncPatch] = useGomokuStore(
    ({ state, syncPatch }) => [
      state.MAX_ROW,
      state.gameStatus,
      state.boardBackground,
      state.borderColor,
      syncPatch,
    ],
    shallow,
  )

  const [dialogVisible, setDialogVisible] = React.useState<boolean>(false)

  const events = {
    onCancel: useEvent((): void => {
      settingsRef.current?.reset()
      setDialogVisible(false)
    }),
    onConfirm: useEvent((): void => {
      const data = settingsRef.current?.getData()
      if (data != null) {
        syncPatch(() => ({
          MAX_ROW: data.size,
          MAX_COL: data.size,
          boardBackground: data.background,
          borderColor: data.border,
        }))
      }
      setDialogVisible(false)
    }),
    onOpenDialog: useEvent((): void => setDialogVisible(true)),
  }

  const isPending: boolean = gameStatus === GameRunningStatus.PENDING
  const isEditable: boolean = gameStatus === GameRunningStatus.PENDING

  const { WakeBtn = DefaultWakeBtn } = props
  return (
    <div className={cx(classes.container, props.className)}>
      <WakeBtn onWakeUp={events.onOpenDialog} />
      <Dialog
        container={props.containerRef.current}
        open={dialogVisible}
        onClose={events.onCancel}
        aria-labelledby="edit-player"
      >
        <DialogContent className={classes.dialog}>
          <GameSettings
            ref={settingsRef}
            disabled={!isPending}
            size={MAX_ROW}
            background={boardBackground}
            border={borderColor}
          />
        </DialogContent>
        <DialogActions>
          <Button color="inherit" onClick={events.onCancel}>
            Cancel
          </Button>
          <Button color="primary" disabled={!isEditable} onClick={events.onConfirm}>
            Confirm
          </Button>
        </DialogActions>
      </Dialog>
    </div>
  )
}

const classes = mergeStyleSets({
  container: {},
  dialog: {
    minWidth: 200,
    minHeight: 300,
  },
  wakeBtn: {
    '> svg': {
      width: 18,
      height: 18,
    },
  },
})
