import { css } from '@emotion/css'
import { useThrowRandomConfetti } from '@kyokuya/react-confetti'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import GamePausedIcon from '@mui/icons-material/PauseCircleFilled'
import GamePendingIcon from '@mui/icons-material/PlayArrow'
import GameRefreshIcon from '@mui/icons-material/Refresh'
import Button from '@mui/material/Button'
import React from 'react'
import shallow from 'zustand/shallow'
import { GomokuContextType } from '../context/Provider'
import type { IGomokuPlayer } from '../types'

export const GameOverlay: React.FC = () => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [winnerIdx, gameStatus, players, action] = useGomokuStore(
    store => [store.state.winner, store.state.gameStatus, store.state.players, store.action],
    shallow,
  )
  const throwConfetti = useThrowRandomConfetti()
  const classes = useStyles()

  const winner: IGomokuPlayer | undefined = players[winnerIdx]
  React.useEffect(() => {
    if (gameStatus === GameRunningStatus.FINISHED && winner !== undefined) {
      void throwConfetti()
    }
  }, [gameStatus, winner, throwConfetti])

  return React.useMemo(() => {
    switch (gameStatus) {
      case GameRunningStatus.PENDING: {
        return (
          <div className={classes.overlay}>
            <Button
              className={classes.button}
              variant="contained"
              color="primary"
              startIcon={<GamePendingIcon />}
              onClick={action.start}
            >
              Start
            </Button>
          </div>
        )
      }
      case GameRunningStatus.PAUSED: {
        return (
          <div className={classes.overlay}>
            <Button
              className={classes.button}
              variant="contained"
              color="primary"
              startIcon={<GamePausedIcon />}
              onClick={action.resume}
            >
              Resume
            </Button>
          </div>
        )
      }
      case GameRunningStatus.FINISHED: {
        return (
          <div className={classes.overlay}>
            <div className={classes.finishedBanner}>
              {winner !== undefined ? (
                <p>
                  <span className={classes.playerName}>{winner.name}</span> win 🎉🎉🎉
                </p>
              ) : (
                <p>Draw!</p>
              )}
              <Button
                className={classes.button}
                variant="contained"
                color="primary"
                startIcon={<GameRefreshIcon />}
                onClick={action.restart}
              >
                New
              </Button>
            </div>
          </div>
        )
      }
      default:
        return null
    }
  }, [gameStatus, classes, action, winner])
}

const useStyles = () => {
  return React.useMemo(
    () => ({
      overlay: css`
        position: relative;
        display: flex;
        align-items: center;
        justify-content: center;
        height: 100%;
        width: 100%;
        user-select: none;
      `,
      confettiCanvas: css`
        position: absolute;
        top: 0;
        bottom: 0;
        left: 0;
        right: 0;
        width: 100%;
        height: 100%;
      `,
      button: css`
        &&, &&:hover {
          box-shadow: 4px 4px 16px 0px hsl(0deg 0% 0% / 0.75);
        }
      `,
      finishedBanner: css`
        position: relative;
        display: flex;
        flex-direction: column;
        justify-content: center;
        padding: 0;
        margin: 0;
        font-size: 32px;
      `,
      playerName: css`
        color: #e200e2;
      `,
    }),
    [],
  )
}
