import { Loading } from '@kyokuya/core-component'
import { assign, pick } from '@kyokuya/core-util'
import { useAsyncState } from '@kyokuya/react-storage'
import PropTypes from 'prop-types'
import React from 'react'
import { GomokuPersistent } from './container/GomokuPersistent'
import { GomokuContextProvider } from './context/Provider'
import type { IGomokuState as IState } from './context/state'
import { initGomokuState } from './context/state'
import { GomokuGameMain } from './GomokuGameMain'

export interface IGomokuGameProps {
  storageKey?: string
  initialState?: Partial<IState> | Promise<Partial<IState>>
}

export const GomokuGame: React.FC<IGomokuGameProps> = props => {
  const { loading, data, save } = useAsyncState<IState>(props.storageKey, {
    deserialize: async initialData =>
      initGomokuState(assign<Partial<IState>>({ ...initialData }, await props.initialState)),
    serialize: latestData =>
      pick(latestData, [
        'MAX_ROW',
        'MAX_COL',
        'players',
        'winner',
        'instructions',
        'boardBackground',
        'borderColor',
        'gameTick',
      ]),
  })

  if (loading) return <Loading />

  return (
    <GomokuContextProvider initialState={data}>
      <GomokuPersistent onStateChange={save} />
      <GomokuGameMain />
    </GomokuContextProvider>
  )
}

GomokuGame.propTypes = {
  storageKey: PropTypes.string.isRequired,
  initialState: PropTypes.any,
}
